sys_script_include.script:
var TaniumActionUtil = Class.create();
TaniumActionUtil.prototype = Object.extendsObject(x_taniu_tan_core.TaniumIntegrationCore, {

	/**
	 * Creates a single Tanium Action, targeted to a single endpoint's serial number.
	 * @param {String|Number} packageID - The Package ID of the Tanium Package to deploy to the
	 *  endpoint with this Action. As demonstrated in the example code below, the Package ID
	 *  can be found in the x_taniu_tan_core_tanium_package table.
	 * In the related list below the form on the Tanium Package table, you can also find a
	 *  list of valid parameters for each package, which you can use to construct the
	 *  optional parametersObj argument.
	 * @param {String} endpointSerial - The serial number of the endpoint to which you'd like
	 *  to target this action.
	 * Note that this assumes that, as they should be, endpoint serial numbers are unique
	 *  within your environment. If this is not the case, that could result in multiple
	 *  endpoints being targeted. If you need to use alternate targeting, some custom
	 *  development may be required depending on which specific property you'd like to use
	 *  to target your action.
	 * @param {Object} [parametersObj={}] - An object containing the parameters to be passed
	 *  into the Tanium Package specified for your Action in the packageID argument. This
	 *  should take the form of a JSON object where each key (property name) is set to the
	 *  value of the key field on the Tanium Package Parameter associated to the Tanium
	 *  Package with the ID specified in the packageID argument.
	 * Example, using the $1 parameter key from the "Custom Tagging - Add Tags"
	 *  Package:
	 * {
	 *    '$1' : 'tag_name_here'
	 * }
	 * Some Tanium Packages may require one or more parameters, and some may require none.
	 *  If there are required parameters that are not specified, an error may occur. Be sure
	 *  to test which parameters you're passing to each package before promoting your code
	 *  to production.
	 * Any parameters passed into the createActionOnEndpointBySerial() method using this
	 *  argument that are not valid parameters according to the Tanium Package Parameter
	 *  table will result in an error, and the code will halt.
	 * You can learn about packages and parameters in the Tables section of the documentation.
	 * @param {Number} [expireSeconds=86400] - The number of seconds after which the Action
	 *  will expire. If the endpoint is offline when this Action is issued, and remains
	 *  offline for the duration in expireSeconds, the Action will not be deployed on that
	 *  endpoint.
	 * Default value: 86,400 (24 hours)
	 * @param {Boolean} [ignoreInvalidParams=false] - Optionally specify whether to ignore
	 *  invalid parameters. If set to true, this will prevent any form of parameter validation
	 *  on the ServiceNow side.
	 * This can be useful for when you're interacting with certain sensor-sourced packages,
	 *  such as the "Custom Tagging - Remove Tags" package, which requires a non-declared
	 *  parameter "||Custom Tags||".
	 * @return {Object|Boolean} - The response body when the REST call to create the
	 *  Tanium Action is called, including the Action ID from Action History in Tanium
	 *  in the .data.id node.
	 * If there is an error, then the boolean false will be returned or an error will be
	 *  thrown depending on severity.
	 *  @example
	 *  deployTagToEndpoint();
	 *
	 * function deployTagToEndpoint() {
	 *    var errMsg, tic, params, computerSerialNumber, grPackage, packageName, actionResponse;
	 *    tic = new x_taniu_tan_core.TaniumActionUtil();
	 *    params = { //Key is parameter key, value is parameter value.
	 *       '$1' : 'integration_core_is_cool' //Tag name
	 *    }; //Parameter keys (and descriptions) can be found in related list under Tanium Packages
	 *     var computerSerialNumber = 'some_serial_number';
	 *     packageName = 'Custom Tagging - Add Tags';
	 *
	 *    grPackage = new GlideRecord('x_taniu_tan_core_tanium_package');
	 *    grPackage.addQuery('name', packageName);
	 *    grPackage.setLimit(1);
	 *    grPackage.query();
	 *
	 *    if (!grPackage.next()) {
	 *       errMsg = 'Package with name ' + packageName + ' not found in Tanium Package table.';
	 *       gs.error(errMsg);
	 *       throw new Error(errMsg);
	 *    }
	 *
	 *    actionResponse = tic.createActionOnEndpointBySerial( //Create action in Tanium
	 *       grPackage.getValue('package_id'), //ID for "Custom Tagging - Add Tags" package
	 *       computerSerialNumber,
	 *       params
	 *    );
	 *
	 *    gs.info(
	 *       'Tanium Action created with ID ' + actionResponse.data.id.toString()
	 *    );
	 * }
	 *
	 * @version 1.4.3 - Updated to use new system property (x_taniu_tan_core.all_computers_action_group_id) to determine the "Default - All Computers" action group ID.
	 */
	createActionOnEndpointBySerial : function (
		packageID,
		endpointSerial,
		parametersObj,
		expireSeconds,
		ignoreInvalidParams
	) {
		//init: hoist
		var logMsg,
			errMsg,
			grPackage,
			actionGroupID,
			packageName,
			rCreateAction,
			responseObj,
			specifiedParameterKeys,
			parametersArr,
			paramValidationResponse;

		//Set default arg values if unspecified
		parametersObj = (typeof parametersObj == 'undefined') ? {} : parametersObj;
		expireSeconds = (typeof expireSeconds == 'undefined') ? 86400 : expireSeconds;
		ignoreInvalidParams = (typeof ignoreInvalidParams == 'undefined') ? false : ignoreInvalidParams;

		actionGroupID = parseInt(
			gs.getProperty(
				'x_taniu_tan_core.all_computers_action_group_id',
				'4'
			)
		) || 4;

		specifiedParameterKeys = Object.keys(parametersObj);
		parametersArr = this._transformParametersObjToArray(parametersObj);

		if (!ignoreInvalidParams) {
			//Check that all specified parameters are valid for this package.
			paramValidationResponse = this._checkAllParametersAreValidForPackage(
				packageID,
				specifiedParameterKeys
			);
			if (paramValidationResponse.has_error) {
				errMsg = 'Parameters specified when calling function to create Tanium Action ' +
					'are invalid. Error info:\n' +
					JSON.stringify(paramValidationResponse, null, 2);
				gs.error(errMsg);
				throw new Error(errMsg);
			}
		}

		grPackage = this._getPackageGRByID(packageID);
		if (!grPackage.next()) {
			errMsg = 'Unable to find Tanium Package in Tanium Package table with package ID ' +
				packageID;
			gs.error(errMsg);
			throw new Error(errMsg);
		}

		packageName = grPackage.getValue('name');

		rCreateAction = this._getRESTObject(
			'Tanium Integration Core',
			'Action-Create Action on CI'
		);

		rCreateAction.setStringParameterNoEscape(
			'tanium_api_endpoint',
			this.TANIUM_API_ENDPOINT
		);
		rCreateAction.setStringParameterNoEscape(
			'computer_serial_number',
			endpointSerial
		);
		rCreateAction.setStringParameterNoEscape(
			'all_computers_action_group_id',
			actionGroupID
		);
		rCreateAction.setStringParameterNoEscape(
			'package_id',
			grPackage.getValue('package_id')
		);
		rCreateAction.setStringParameterNoEscape(
			'package_name',
			packageName
		);
		rCreateAction.setStringParameterNoEscape(
			'action_name',
			grPackage.getValue('name')
		);
		rCreateAction.setStringParameterNoEscape(
			'parameters_array',
			JSON.stringify(parametersArr)
		);
		rCreateAction.setStringParameterNoEscape('expire_seconds', expireSeconds.toString());

		responseObj = this._executeRESTCall(rCreateAction);

		logMsg = 'Execute package ' + packageName + ' with package ID ' + packageID + ' on endpoint with serial number ' + endpointSerial + '.';
		if (parametersArr && parametersArr.length > 0) {
			logMsg += '\nAction Parameters:\n' + JSON.stringify(parametersObj, null, 2);
		}
		this._logAction(
			endpointSerial,
			this.getEndpointIDBySerial(endpointSerial),
			packageName,
			logMsg,
			((responseObj.hasOwnProperty('data') && responseObj.data.hasOwnProperty('id')) ? responseObj.data.id : '')
		);

		return responseObj;
	},

	/**
	 * Execute a pre-configured Action from the Configured Action [x_taniu_tan_core_configured_action_package] table.
	 * The selected Configured Action must be active, and have its parameters (if it has any)
	 *  configured within the Configured Action Parameter table (the related list at the bottom
	 *  of the Configured Action form).
	 *
	 * @param {GlideRecord} grConfiguredAction - A GlideRecord positioned to the Configured
	 *  Action record for the specific Configured Action you'd like to execute against the
	 *  target endpoint.
	 * @param {GlideRecord} grEndpoint - A GlideRecord positioned to the endpoint on which
	 *  you'd like to execute the specified Configured Action.
	 * @param {Number} [expireSeconds=86400] - The number of seconds after which the Action
	 *  will expire. If the endpoint is offline when this Action is issued, and remains
	 *  offline for the duration in expireSeconds, the Action will not be deployed on that
	 *  endpoint.
	 * Default value: 86,400 (24 hours).
	 * @param {Object} [parameterArgsObj={}] - An optional object to pass into any Configured
	 *  Action Parameters that use an "advanced" scripted parameter value.
	 * This is not required, and in the vast majority of cases, will not be used.
	 * Default value: {}
	 *
	 * @returns {Object|Boolean} - The response body when the REST call to create the
	 *  Tanium Action is called, including the Action ID from Action History in Tanium
	 *  in the .data.id node.
	 * If there is an error, then the boolean false will be returned or an error will be
	 *  thrown depending on severity.
	 *
	 * @example
	 * var createActionResponse;
	 * var tau = new x_taniu_tan_core.TaniumActionUtil();
	 * var grEndpoint = new GlideRecord('cmdb_ci_win_server');
	 * var grConfiguredAction = new GlideRecord('x_taniu_tan_core_configured_action_package');
	 *
	 * grEndpoint.get('[endpoint_sys_id_here]');
	 *
	 * //Pre-configured action to apply specific tag
	 * grConfiguredAction.get('[configured_action_sys_id]');
	 *
	 * createActionResponse = tau.executeConfiguredAction(
	 * 	grConfiguredAction,
	 * 	grEndpoint
	 * );
	 *
	 * gs.info(JSON.stringify(
	 * 	createActionResponse,
	 * 	null,
	 * 	2
	 * ));
	 * @since 1.2.0
	 */
	executeConfiguredActionOnEndpoint: function(
		grConfiguredAction,
		grEndpoint,
		expireSeconds,
		parameterArgsObj
	) {
		//upcoming_feature: Break this method into chunks
		var paramKey, paramValue, packageID, grConfiguredActionParam;
		var endpointSerial = grEndpoint.getValue('serial_number');

		parameterArgsObj = (gs.nil(parameterArgsObj)) ? {} : parameterArgsObj;
		expireSeconds = (gs.nil(expireSeconds)) ? 86400 : expireSeconds;

		//BEGIN Check for errors in passed arguments
		//Configured action and endpoint must be valid records.
		if (!grConfiguredAction.isValidRecord() || !grEndpoint.isValidRecord()) {
			throw new Error(
				'Error while executing TaniumActionUtil.executeConfiguredActionOnEndpoint(): ' +
				'Either the "Configured Action" record or the endpoint record passed into ' +
				'this function were not valid records in the database. Halting execution.'
			);
		}
		//Serial number must be specified
		if (!endpointSerial) {
			throw new Error(
				'Error while executing TaniumActionUtil.executeConfiguredActionOnEndpoint(): ' +
				'The specified endpoint with sys_id ' + grEndpoint.getUniqueValue() +
				' has no serial number. Cannot execute Action without a valid serial number.'
			);
		}
		//Configured action must be a record in the correct table.
		if (grConfiguredAction.getTableName() !== 'x_taniu_tan_core_configured_action_package') {
			throw new Error(
				'Error while executing TaniumActionUtil.executeConfiguredActionOnEndpoint(): ' +
				'grConfiguredAction argument does not correspond to a valid Configured Action ' +
				'in the x_taniu_tan_core_configured_action_package table. Instead, the passed ' +
				'GlideRecord corresponds to a record with sys_id ' +
				grConfiguredAction.getUniqueValue() + ' on table ' +
				grConfiguredAction.getTableName() + '. Unable to continue with deploying ' +
				'Configured Action on endpoint with sys_id ' + grEndpoint.getUniqueValue() +
				'. Halting execution.'
			);
		}
		//Prevent executing deactivated Configured Actions
		if (grConfiguredAction.getValue('active') !== '1') {
			throw new Error(
				'Error while executing TaniumActionUtil.executeConfiguredActionOnEndpoint(): ' +
				'The "Configured Action" record is deactivated and cannot be executed.'
			);
		}
		//Prevent executing configured actions without selected action packages.
		if (grConfiguredAction.action_package.nil()) {
			throw new Error(
				'Error while executing TaniumActionUtil.executeConfiguredActionOnEndpoint(): ' +
				'The "Configured Action" record\'s "Action package" field is empty. Cannot ' +
				'execute an action without a valid package. Halting execution.'
			);
		}
		//END argument error checking

		packageID = grConfiguredAction.action_package.package_id.toString();
		//Okay, I lied; one more error-check.
		if (!packageID) {
			throw new Error(
				'Error while executing TaniumActionUtil.executeConfiguredActionOnEndpoint(): ' +
				'The selected Configured Action points to a Tanium Action Package (sys_id: ' +
				grConfiguredAction.getValue('action_package') + ') with no package ID. ' +
				'Cannot continue without a valid package ID.'
			);
		}

		grConfiguredActionParam = new GlideRecord(
			'x_taniu_tan_core_configured_action_parameter'
		);
		grConfiguredActionParam.addQuery(
			'configured_action',
			grConfiguredAction.getUniqueValue()
		);
		grConfiguredActionParam.addNotNullQuery('key');
		grConfiguredActionParam.query();

		//Get all parameter values to use with this package.
		while(grConfiguredActionParam.next()) {
			paramKey = grConfiguredActionParam.getValue('key');
			paramValue = this._getConfiguredActionParamValue(
				grConfiguredActionParam,
				grEndpoint,
				parameterArgsObj
			);

			if (paramValue && (typeof paramValue !== 'string')) {
				paramValue = paramValue.toString();
			}

			if (paramKey && paramValue) {
				parameterArgsObj[paramKey] = paramValue;
			}
		}

		//Finally, we execute the action!
		return this.createActionOnEndpointBySerial(
			packageID,
			endpointSerial,
			parameterArgsObj,
			expireSeconds,
			true
		);
	},

	/**
	 * Stop the specified action (by actionID) after the specified number of endpoints
	 *  (numEndpoints) or more have completed the action.
	 * @param {String|Number} actionID - The action ID to stop after the specified number of
	 *  endpoints have completed it.
	 * @param {Number} numEndpoints -The number of endpoints to have completed the specified
	 *  action, after which the action should be stopped.
	 */
	stopActionAfterCompletedOn : function (actionID, numEndpoints) {
		var inputs = {
			'tan_action_id' : actionID.toString(),
			'min_completion_count' : numEndpoints
		};

		// Start Asynchronously: Uncomment to run in background. Code snippet will not have access
		// to outputs.
		// sn_fd.FlowAPI.getRunner().subflow('x_taniu_tan_core.taniumstop_action_after_n_endpoints').inBackground().withInputs(inputs).run();

		// Execute Synchronously: Run in foreground. Code snippet has access to outputs.
		var result = sn_fd.FlowAPI.getRunner()
			.subflow('x_taniu_tan_core.taniumstop_action_after_n_endpoints')
			.withInputs(inputs)
			.run();

		return result;
	},

	/**
	 * Immediately stop the specified action (by actionID).
	 * @param {String|Number} actionID - The "action ID" of the Tanium Action to stop.
	 * @returns {boolean}
	 */
	stopActionByID : function (actionID) {
		var responseBody;
		var rStopActionByID = this._getRESTObject(
			'Tanium Integration Core',
			'Action-Stop Action'
		);

		rStopActionByID.setStringParameterNoEscape(
			'action_id', actionID
		);
		rStopActionByID.setStringParameterNoEscape(
			'tanium_api_endpoint', this.TANIUM_API_ENDPOINT
		);


		/*
		   This API call is intermittently returning status 0 on on-prem instances.
		   Unable to identify the cause. Further investigation required.
		   Probably not an issue on the SN side.
		   For now, setting ignoreHTTPErrors and returnFalseOnFailure to true to prevent halting.
		 */
		responseBody = this._executeRESTCall(
			rStopActionByID, true, true, true
		);

		return !!responseBody;
	},

	/**
	 * Get details about the specified package, by package name.
	 * @param {String} packageName - The name of the package you want details about.
	 * @param {String} [contentSetName=] - If specified, only Tanium Packages which are part of
	 *     this Content Set will be included in the returned array. If unspecified, Tanium Packages
	 *     in all Content Sets will be included.
	 * @param getParameters
	 * @returns {[{}]}
	 */
	getPackageDetailsByName : function (packageName, contentSetName, getParameters) {
		//Verify that the caller has specified the package name. Otherwise, throw.
		if (!packageName) {
			throw new Error(
				'getPackageDetailsByName called without specifying packageName parameter. ' +
				'Package name is required to get package details by name.'
			);
		}
		getParameters = (typeof getParameters == 'undefined') ? true : getParameters;

		//init variables
		var packageDetails = [];
		var grPackage = new GlideRecord('x_taniu_tan_core_tanium_package');
		//Add query param for name. If contentSetName is specified, specify that as well.
		grPackage.addQuery('name', packageName);
		if (contentSetName) {
			grPackage.addQuery('content_set_name', contentSetName);
		}
		grPackage.query();

		//For each returned package, construct an object with all relevant details about
		// that package, and push it into the array to be returned.
		while (grPackage.next()) {
			packageDetails.push({
				'name' : grPackage.getValue('name'),
				'id' : grPackage.getValue('package_id'),
				'command' : grPackage.getValue('command'),
				'content_set_name' : grPackage.getValue('content_set_name'),
				'content_set_id' : grPackage.getValue('content_set_id'),
				'parameters' : (getParameters) ?
					this.getParameterDetailsByPackageSysID(
						grPackage.getUniqueValue()
					) : []
			});
		}

		return packageDetails;
	},

	/**
	 * Get parameter details by package sys_id. Gets all important details about all parameters
	 *  associated with the specified Tanium Package as an array of objects. If package has no
	 *  parameters, a blank array (with 0 elements) is returned instead.
	 * @param {String} packageSysID - The sys_id of the Tanium Package to get all parameter
	 *  details for. This should be the sys_id of a record in the x_taniu_tan_core_tanium_package
	 *  table.
	 * @returns {[{}]} An array of objects with details about all parameters associated with
	 *  the specified package. If no parameters are accepted for the specified package, an empty
	 *  array will be returned instead.
	 */
	getParameterDetailsByPackageSysID : function (packageSysID) {
		if (!packageSysID) {
			throw new Error(
				'getParameterDetailsByPackageSysID() called without specifying packageSysID ' +
				'argument. Package sys_id is required to get a package\'s parameters.'
			);
		}
		var paramDetails = [];
		var grPackageParam = new GlideRecord('x_taniu_tan_core_tanium_package_parameter');

		grPackageParam.addQuery('package', packageSysID);
		grPackageParam.query();

		while (grPackageParam.next()) {
			paramDetails.push({
				'label' : grPackageParam.getValue('label'),
				'param_key' : grPackageParam.getValue('key'),
				'description' : grPackageParam.getValue('description'),
				'default_value' : grPackageParam.getValue('default_value'),
				'max_characters' : parseInt(grPackageParam.getValue('max_characters')) || 0
			});
		}

		return paramDetails;
	},


	/**
	 * Get the details of a specific action which has previously been triggered against one
	 *  or more endpoints.
	 * @param {String} actionID - The ID of the action (not to be confused with the ID of
	 *  the package) that was previously deployed. You can get this from the .data.id node
	 *  of the object returned from the .createActionOnEndpointBySerial() method.
	 * @return {Object|Boolean} - The response body from the API call to Tanium.
	 */
	getActionDetailsByID : function (actionID) {
		var responseBody;
		var rGetActionDetailsByID = this._getRESTObject(
			'Tanium Integration Core',
			'Action-Get Action Details by ID'
		);

		rGetActionDetailsByID.setStringParameterNoEscape(
			'action_id', actionID
		);
		rGetActionDetailsByID.setStringParameterNoEscape(
			'tanium_api_endpoint', this.TANIUM_API_ENDPOINT
		);

		/*
		   This API call is intermittently returning status 0 on on-prem instances.
		   Unable to identify the cause. Further investigation required.
		   Probably not an issue on the SN side.
		   For now, setting ignoreHTTPErrors and returnFalseOnFailure to true to prevent halting.
		 */
		responseBody = this._executeRESTCall(
			rGetActionDetailsByID, true, true, true
		);

		return responseBody;
	},

	/**
	 * Get the results (so far) of a specific action which has previously been issued.
	 * @param {String|Number} sourceID - The ID of the action (not to be confused with the ID of
	 *  the package) that was previously deployed. You can get this from the .data.id node of the
	 *  object returned from the .createActionOnEndpointBySerial() method.
	 * @returns {Object|Boolean} - The response body from the API call to Tanium.
	 * Returns false if the API call fails.
	 */
	getActionResultsBySourceID: function (sourceID) {
		var responseBody;
		var rGetActionResultsByID = this._getRESTObject(
			'Tanium Integration Core',
			'Action-Get Action Results by Source ID'
		);

		rGetActionResultsByID.setStringParameterNoEscape(
			'tanium_module_api_url', this.TANIUM_MODULE_API_ENDPOINT
		);
		rGetActionResultsByID.setStringParameterNoEscape(
			'source_id', sourceID
		);

		responseBody = this._executeRESTCall(
			rGetActionResultsByID, true, true, true
		);

		gs.info(
			'TaniumActionUtil.getActionResultsBySourceID() response body: \n' +
			JSON.stringify(responseBody, null, 2)
		);

		return responseBody;
	},

	getActionResultsByID : function (actionID) {
		var responseBody;
		var rGetActionResultsByID = this._getRESTObject(
			'Tanium Integration Core',
			'Action-Get Action Results by ID'
		);

		rGetActionResultsByID.setStringParameterNoEscape(
			'tanium_api_endpoint', this.TANIUM_API_ENDPOINT
		);
		rGetActionResultsByID.setStringParameterNoEscape(
			'action_id', actionID
		);


		/*
		   This API call is intermittently returning status 0 on on-prem instances.
		   Unable to identify the cause. Further investigation required.
		   Probably not an issue on the SN side.
		   For now, setting ignoreHTTPErrors and returnFalseOnFailure to true to prevent halting.
		 */
		responseBody = this._executeRESTCall(
			rGetActionResultsByID, true, true, true
		);

		return responseBody;
	},

	/**
	 * Update the Tanium Package and Tanium Package Parameter tables
	 *  (x_taniu_tan_core_tanium_package and x_taniu_tan_core_tanium_package_parameter
	 *  respectively).
	 * This method is called by the Scheduled Script Execution "Sync Tanium Packages and Package
	 *  Parameters for Actions", which should have the sys_id "00d7b0dc2f2f70501ba85d492799b6b1".
	 * @param {Boolean} [skipHiddenPackages=true] Optionally specify whether to skip (not import)
	 * packages which are marked in Tanium as "hidden".
	 * @param {Boolean} [skipDeletedPackages=true] Optionally specify whether to skip (not import)
	 *  packages which are marked in Tanium as "deleted".
	 * @return {boolean} Returns boolean true if successful. Throws an error and logs to the system
	 *  error logs, if this process fails.
	 */
	updatePackagesTable : function (skipHiddenPackages, skipDeletedPackages) {
		var allPackages;

		skipHiddenPackages = (typeof skipHiddenPackages == 'undefined') ? true : skipHiddenPackages;
		skipDeletedPackages = (typeof skipDeletedPackages == 'undefined') ? true : skipDeletedPackages;

		//Get all packages from Tanium
		allPackages = this._getAllPackageDetails();

		//Update any packages in the Tanium Packages table that need updating.
		//Delete any packages in the table that weren't in this latest export.
		//NOTE: This method modifies allPackages in-place, removing any that were
		// updated or deleted, so all package objects remaining in it should be created.
		this._updateAndDeleteExistingPackages(
			allPackages,
			skipHiddenPackages,
			skipDeletedPackages
		);

		this._createAllMissingPackages(
			allPackages,
			skipHiddenPackages,
			skipDeletedPackages
		);

		return true;
	},

	/**
	 * Kill the specified process with the specified process name and ID, on the specified
	 * endpoint.
	 * All arguments are mandatory. A hard error will be thrown if all arguments are not specified.
	 *
	 * @param {String} endpointSerialNumber - The serial number of the endpoint (must be unique
	 *  in your environment).
	 * @param {String} processName - The process name. For example: "notepad.exe".
	 * @param {Number|String} processID - The process ID as either an integer or a string.
	 * For example, 8141 or "8141".
	 * @param {Number|String} [endpointID=this.getEndpointIDBySerial(endpointSerialNumber)] -
	 *  Optionally specify the endpoint ID. If this is not specified, endpointSerialNumber
	 *  must be. If it IS specified, endpointSerialNumber is not used.
	 * @return {boolean} - True if the process was successfully killed, or false if not (in which
	 *  case, a WARNING will likely be logged to your system logs - such as if the process cannot
	 *  be found).
	 * @example
	 * var i, notepadPID;
	 * var computerSerialNumber = 'some_serial_number';
	 * var tanActionUtil = new x_taniu_tan_core.TaniumActionUtil();
	 * var endpointID = tanActionUtil.getEndpointIDBySerial(computerSerialNumber);
	 * notepadPID = tanActionUtil.getProcessIDsByName(null, 'notepad.exe', endpointID)[0];
	 * //Optionally, use endpoint serial instead:
	 * //notepadPID = tanActionUtil.getProcessIDsByName(computerSerialNumber, 'notepad.exe')[0];
	 * tanActionUtil.killProcessOnEndpoint(
	 *    null, //Optionally, specify the computer serial number and skip endpointID
	 *    'notepad.exe',
	 *    notepadPID,
	 *    endpointID
	 * );
	 */
	killProcessOnEndpoint : function (
		endpointSerialNumber,
		processName,
		processID,
		endpointID
	) {
		var responseBody,
			rKillProcess,
			responseIsValid;

		//Validate inputs
		if ((!endpointSerialNumber && !endpointID) || !processName || !processID) {
			throw new Error(
				'TaniumIntegrationCore.killProcessOnEndpoint() called with invalid arguments.'
			);
		}

		//Get endpoint ID using the provided serial number.
		if (!endpointID) {
			endpointID = this.getEndpointIDBySerial(endpointSerialNumber);
		}
		//Initialize "kill process" REST Message object; automatically handle auth session.
		rKillProcess = this._getRESTObject('Tanium Integration Core', 'Gateway-Kill Process');

		rKillProcess.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rKillProcess.setStringParameterNoEscape('endpoint_id', endpointID);
		rKillProcess.setStringParameterNoEscape('process_id', processID);
		rKillProcess.setStringParameterNoEscape('process_name', processName);

		//Execute REST call to Tanium (may do a hard throw if response body invalid or server
		// unavailable)
		responseBody = this._executeRESTCall(rKillProcess);
		responseIsValid = (
			( //Response has non-null data node
				responseBody.hasOwnProperty('data') &&
				responseBody.data
			) &&
			( //Response has non-null data.killProcess node
				responseBody.data.hasOwnProperty('killProcess') &&
				responseBody.data.killProcess
			) &&
			( //Response has non-null data.killProcess.result node
				responseBody.data.killProcess.hasOwnProperty('result') &&
				responseBody.data.killProcess.result
			)
		);
		//If result node (or any parent nodes) not found, return false.
		if (!responseIsValid) {
			gs.error(
				'Attempting to kill process ' + processName + ' with process ID ' +
				processID + ' on endpoint with serial number ' + endpointSerialNumber + ' failed. ' +
				'This could be due to the specified process not running on the target system. \n' +
				'Response body: \n' +
				((responseBody && typeof responseBody === 'object') ? JSON.stringify(responseBody, null, 2) : '')
			);
			this._logAction(
				endpointSerialNumber,
				endpointID,
				'Kill Process',
				(
					'Kill process ' + processName + ' with process ID ' + processID +
					' on endpoint with serial number ' + endpointSerialNumber + '.\n' +
					'ERROR: Response body did not contain expected data.killProcess.result node.\n' +
					'Response body: \n' +
					(
						(responseBody && typeof responseBody === 'object') ?
							JSON.stringify(responseBody, null, 2) :
							'{}'
					)
				),
				'',
				false
			);

			return false;
		}

		this._logAction(
			endpointSerialNumber,
			endpointID,
			'Kill Process',
			'Kill process ' + processName + ' with process ID ' + processID + ' on endpoint with serial number ' + endpointSerialNumber + '.',
			'',
			!!responseBody.data.killProcess.result
		);

		//Return result node value cast to boolean
		return !!responseBody.data.killProcess.result;
	},

	/**
	 * Reboot a specific endpoint by Endpoint ID.
	 * @param {String|Number} endpointID - The endpoint ID, which can be found by calling
	 *  TaniumIntegrationCore.getEndpointIDBySerial() if not known.
	 * NOTE: Since the TaniumActionUtil Script Include extends TaniumIntegrationCore, you can call
	 *  the .getEndpointIDBySerial() method of this SI as well.
	 * @param {("Windows"|"Linux"|"Mac"|"Solaris"|"AIX")} endpointOS - The operating system of the
	 *  specified endpoint. Must be one of the enumerated values:
	 *  Windows, Linux, Mac, Solaris, AIX
	 * @return {Number|string} The Action ID for the action that was created to reboot the
	 *  endpoint. This can be passed into TaniumActionUtils.getActionDetailsByID() to get the
	 *  action status.
	 * @example
	 * var actionUtil = new x_taniu_tan_core.TaniumActionUtil();
	 * var endpointID = actionUtil.getEndpointIDBySerial('some_serial_number'); //1 var
	 *     actionHistoryID = actionUtil.rebootEndpoint(endpointID,
	 *     'Windows'); gs.info('Action history ID: ' + actionHistoryID);
	 * //...
	 * //This may result in HTTP status 0 (which may cause the code to throw an error) if called
	 *     *immediately* after creating the action. var actionResult =
	 *     actionUtil.getActionDetailsByID(actionHistoryID); gs.info(actionResult);
	 */
	rebootEndpoint : function (endpointID, endpointOS) {
		var rRebootEndpoint, rebootResponse;
		var validOperatingSystems = [
			'Windows',
			'Linux',
			'Mac',
			'Solaris',
			'AIX'
		];

		//If OS is not specified or is not a valid Operating System Tanium supports, throw.
		if ((!endpointOS) || (validOperatingSystems.indexOf(endpointOS) < 0)) {
			throw new Error(
				'Error attempting to reboot endpoint with ID ' + endpointID +
				'. Specified operating system (' + endpointOS + ') not found in list of valid ' +
				'operating systems (' + JSON.stringify(validOperatingSystems) + ').'
			);
		}

		rRebootEndpoint = this._getRESTObject(
			'Tanium Integration Core',
			'Gateway-Reboot Endpoint'
		);

		rRebootEndpoint.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rRebootEndpoint.setStringParameterNoEscape(
			'endpoint_id',
			endpointID
		);
		rRebootEndpoint.setStringParameterNoEscape(
			'operating_system',
			endpointOS
		);

		rebootResponse = this._executeRESTCall(
			rRebootEndpoint
		); //throws if call fails

		//If response doesn't contain necessary data, throw. If so, return action history ID.
		if (
			!rebootResponse.hasOwnProperty('data') ||
			!rebootResponse.data.hasOwnProperty('createAction') ||
			!rebootResponse.data.createAction.hasOwnProperty('id')
		) {
			throw new Error(
				'Error attempting to reboot endpoint with ID ' + endpointID +
				'. Could not get action history ID. Got response: \n' +
				JSON.stringify(rebootResponse)
			);
		}

		this._logAction(
			this.endpoint_serial_number || '',
			endpointID,
			'Reboot Endpoint',
			'Reboot ' + endpointOS + ' machine with Tanium endpoint ID ' + endpointID + '.',
			rebootResponse.data.createAction.id
		);

		return rebootResponse.data.createAction.id.toString();
	},

	/**
	 * Restart a specified service on a specified endpoint.
	 * NOTE: This requires the "Distribute Application Management Tools" package be distributed to
	 *  the target endpoints. This means setting the target group for the "Distribute Application
	 *  Management Tools" action to something other than "Default" in Tanium, which contains no
	 *  computers.
	 * @param {String} serviceName The <i>exact</i> technical service name of the service to
	 *     restart. This must be the exact SERVICE NAME, not the "Display name". For example, if
	 *     you wanted to restart the Telephony service, you would not input "Telephony" here, but
	 *     would instead write
	 *  "TapiSrv" (the "Service name" of the Windows Telephony service).
	 * @param {String|Number} endpointID The Tanium endpoint ID, which can be found by calling
	 *  TaniumIntegrationCore.getEndpointIDBySerial() if not known.
	 * NOTE: Since the TaniumActionUtil Script Include extends TaniumIntegrationCore, you can call
	 *  the .getEndpointIDBySerial() method of this SI as well.
	 * @param {"Windows"|"Linux"|"Mac"|"Solaris"|"AIX"|"Unknown"} [platform="Windows"] The platform
	 *  of the target machine on which to perform this action. Must be one of the enumerated
	 *  values. For this method, it is recommended to leave this argument blank, so it only runs
	 *  on Windows machines.
	 * If not specified, this argument defaults to "Windows".
	 * @return {String} The "Action ID" of the Tanium Action that was created for this task.
	 */
	restartService : function (serviceName, endpointID, platform) {
		//Set default param value
		platform = (typeof platform == 'undefined') ? 'Windows' : platform;

		var enumPlatforms = ['Windows', 'Linux', 'Mac', 'Solaris', 'AIX', 'Unknown'];
		var actionID, restartServiceResponse;
		var rRestartService = this._getRESTObject(
			'Tanium Integration Core',
			'Action-Restart Service'
		);
		endpointID = endpointID.toString();

		//Check for errors
		if (enumPlatforms.indexOf(platform) < 0) {
			throw new Error(
				'Error restarting service. Invalid platform "' + platform + '" specified in ' +
				'argument. Valid platforms:\n' +
				' -' + enumPlatforms.join('\n -')
			);
		}
		if (serviceName.indexOf(' ') >= 0) {
			throw new Error(
				'Error restarting service. Invalid service name "' + serviceName + '" specified ' +
				'in argument. Spaces are not allowed in the service name. Please be sure to ' +
				'specify the technical "Service Name" and not the "Service display name"'
			);
		}

		rRestartService.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rRestartService.setStringParameterNoEscape(
			'service_name',
			serviceName
		);
		rRestartService.setStringParameterNoEscape(
			'endpoint_id',
			endpointID
		);
		rRestartService.setStringParameterNoEscape(
			'platform',
			platform
		);

		//throws if call fails
		restartServiceResponse = this._executeRESTCall(rRestartService);

		//Validate response - throw error if not.
		if (
			!restartServiceResponse.hasOwnProperty('data') ||
			!restartServiceResponse.data.hasOwnProperty('createAction') ||
			!restartServiceResponse.data.createAction.hasOwnProperty('id')
		) {
			throw new Error(
				'Error attempting to restart service ' + serviceName + ' on endpoint with ID ' +
				endpointID + '. Could not get action history ID. Got response: \n' +
				JSON.stringify(restartServiceResponse)
			);
		}

		actionID = restartServiceResponse.data.createAction.id.toString();

		this._logAction(
			this.endpoint_serial_number || '',
			endpointID,
			'Restart Service',
			'Restart service ' + serviceName + ' on ' + platform + ' machine with Tanium endpoint ID ' + endpointID + '.',
			actionID
		);

		return actionID;
	},

