	/**
	 * Quarantining endpoints requires that the Tanium Threat Response module be licensed,
	 *  imported, and configured.
	 * For help with the Tanium Threat Response module configuration or troubleshooting, please
	 *  contact your TAM.
	 *
	 * NOTE:
	 * As per the Tanium documentation, in order for this to work, you must have configured the
	 *  "taniumquarantine.dat" file that's associated with each quarantine package (for Windows,
	 *  Linux, and Mac) in your Tanium environment.
	 * Note also that your quarantine packages may be custom, as recommended by the
	 *  documentation, and may have been copied from the following packages in your Tanium
	 *  environment:
	 * 1.	Apply Windows IPsec Quarantine
	 * 2.	Apply Linux IPTables Quarantine
	 * 3.	Apply Mac PF Quarantine
	 * If you've set up custom quarantine packages (which is recommended!) then you'll need to
	 *  update the values of the quarantine package names in the Tanium Integration Core settings.
	 * https://docs.tanium.com/threat_response/threat_response/isolating_endpoints.html
	 *
	 * @param {String} endpointSerial - The serial number of the endpoint to be quarantined.
	 * @param {"Windows"|"Linux"|"Mac"} operatingSystem - The operating system of the endpoint to
	 *  be quarantined.
	 * Must be one of the enumerated and supported operating systems as a string
	 *  (Windows, Linux, or Mac).
	 * (Not case-sensitive).
	 * @param {boolean} [removeQuarantine=false] - If this argument is not specified (or
	 *  if it is set to false), then the target endpoint will be QUARANTINED based on the
	 *  settings configured in the taniumquarantine.dat file associated with the quarantine
	 *  package in your instance, as specified in the quarantine system properties.
	 * If this argument is instead set to true, then - if the endpoint is already quarantined
	 *  - that quarantine will be REMOVED.
	 * Default value: false
	 * @param {Number} [expireSeconds=86400] - The number of seconds after which the Action
	 *  will expire.
	 * If the endpoint is offline when this Action is issued, and remains offline for the
	 *  duration in expireSeconds, the Action will not be deployed on that endpoint.
	 * Default value: 86,400 (24 hours)
	 */
	quarantineEndpointBySerial : function (
		endpointSerial,
		operatingSystem,
		removeQuarantine,
		expireSeconds
	) {
		var quarantinePackageInfo,
			quarantinePackageName,
			quarantinePackageID,
			quarantineResponse;
		var arrValidOperatingSystemsLC = ['windows', 'linux', 'mac', 'macos'];

		expireSeconds = (typeof expireSeconds == 'undefined') ? 86400 : expireSeconds;
		removeQuarantine = (typeof removeQuarantine == 'undefined') ? false : removeQuarantine;

		if (
			!endpointSerial ||
			!operatingSystem ||
			(arrValidOperatingSystemsLC.indexOf(operatingSystem.toLowerCase()) < 0) ||
			!this._isThreatResponseInstalled(true)
		) {
			throw new Error(
				'Error while attempting to quarantine endpoint with serial "' + endpointSerial +
				'", with operating system "' + operatingSystem + '". This could be because ' +
				'Tanium Threat Response is not installed, or because the Endpoint ID or ' +
				'Operating System were not specified when calling the TaniumActionUtil' +
				'.quarantineEndpointByID() method, or because the specified operating ' +
				'system was not one of the supported operating systems (' +
				JSON.stringify(arrValidOperatingSystemsLC) + ').'
			);
		}

		quarantinePackageName = this._getQuarantinePackageNameFromOperatingSystem(
			operatingSystem,
			removeQuarantine
		);
		quarantinePackageInfo = this.getPackageDetailsByName(
			quarantinePackageName,
			null, //Ignore content set name
			false //Improve performance by skipping parameter query
		);

		if (quarantinePackageInfo.length < 1 || !quarantinePackageInfo[0].id) {
			throw new Error(
				'Error while attempting to quarantine endpoint with serial "' + endpointSerial + '", ' +
				'with operating system "' + operatingSystem + '" by calling the ' +
				'TaniumActionUtil.quarantineEndpointByID() method.\n' +
				'Unable to find package with name "' + quarantinePackageName + '" in the ' +
				'Tanium Package [x_taniu_tan_core_tanium_package] table.\n' +
				'This package name was determined by one of the following system properties, ' +
				'depending on the operating system: \n' +
				'-Windows: x_taniu_tan_core.windows_quarantine_package_name\n' +
				'-Linux: x_taniu_tan_core.linux_quarantine_package_name\n' +
				'-Mac: x_taniu_tan_core.mac_quarantine_package_name\n' +
				'If this package was created in Tanium recently, you may need to execute the ' +
				'"Sync Tanium Packages and Package Parameters for Actions" Scheduled Script ' +
				'from the sysauto_script table.'
			);
		}
		quarantinePackageID = quarantinePackageInfo[0].id;

		if (quarantinePackageInfo.length > 1) {
			gs.debug(
				'Got multiple packages from Tanium Package [x_taniu_tan_core_tanium_package] ' +
				'table with name "' + quarantinePackageName + '":\n' +
				JSON.stringify(quarantinePackageInfo, null, 2) + '\n' +
				'Using the first package returned, with ID ' + quarantinePackageID + '.'
			);
		}

		//CREATE QUARANTINE ACTION ON TARGET ENDPOINT:
		quarantineResponse = this.createActionOnEndpointBySerial(
			quarantinePackageID,
			endpointSerial,
			{}, //No parameters necessary; using taniumquarantine.dat file
			expireSeconds,
			true
		);

		return quarantineResponse;
	},

