	/** @private */

	//NOTE: This method and the "Update Tanium Action History Statuses" Scheduled Job which
	// calls it, are disabled and returns false immediately, as this functionality is now
	// controlled by a Flow called "Tanium-Update Action Status".
	/* _updateActionHistoryStatus: function(grActionHistory) {
		//upcoming_feature: implement this method, using this.getActionResultsBySourceID().
	}, */

	/**
	 * Retrieve the value from the Configured Action Parameter in the
	 *  x_taniu_tan_core_configured_action_parameter table.
	 * If the parameter has a static string value, then that will be returned. If the "Advanced"
	 *  checkbox on the Configured Action Parameter record is checked, then the associated script
	 *  will be evaluated and the result will be returned instead.
	 * @param {GlideRecord} grConfiguredActionParam - A GlideRecord on the
	 *  x_taniu_tan_core_configured_action_parameter table, positioned to the specific parameter
	 *  to get the value from.
	 * @param {GlideRecord} [grCurrentCI={}] - A CI to use in the evaluation of an advanced
	 *  configured parameter value script. This can be omitted if none of the parameters use this
	 *  value in their scripts.
	 * @param {Object} [argsObj={}] - Optionally specify an additional object to be passed in
	 *  to the value script, with some additional values in it that can be used when the script
	 *  is evaluated.
	 * @returns {String} - The value from either the "value" field of the Configured Action
	 *  Parameter record, OR the (stringified) result of the evaluation of the script from
	 *  the value_script field (if the Advanced field is set to true).
	 * @private
	 */
	_getConfiguredActionParamValue: function(grConfiguredActionParam, grCurrentCI, argsObj) {
		var gsEval, evalResult;
		grCurrentCI = (typeof grCurrentCI === 'undefined') ? {} : grCurrentCI;
		argsObj = (typeof argsObj != 'object') ? {} : argsObj;

		//If advanced is true, evaluate the script and return the result.
		if (grConfiguredActionParam.getValue('advanced') === '1') {
			gsEval = new GlideScopedEvaluator();

			gsEval.putVariable('currentCI', grCurrentCI);
			gsEval.putVariable('argsObj', argsObj);

			//Considered wrapping this in a 'try/catch' block, but we actually want it to
			// hard-error if this fails, as we don't want the action to continue until the error
			// is resolved.
			evalResult = gsEval.evaluateScript(
				grConfiguredActionParam,
				'value_script'
			);

			//If evalResult is undefined, return blank string. Otherwise, return result.
			try {
				return ((typeof evalResult === 'undefined') || (evalResult === null)) ? '' : evalResult.toString();
			} catch(ex) {
				//If the above fails somehow, just return a blank string.
				//No need to throw or log that error.
				return '';
			}
		}

		//If advanced is not true, return the string value from the 'value' field.
		return grConfiguredActionParam.getValue('value') || '';
	},

	/**
	 * Attempts to determine if Tanium Threat Response solution is installed, and returns
	 *  a boolean with the answer.
	 *
	 * @param {boolean} [returnTrueOnFailure=true] - If unable to determine whether Threat Response
	 *  is enabled, such as if we have insufficient permissions to access installed solutions
	 *  via API, setting this to true (or not specifying it and using the default value) will
	 *  cause this method to assume that Threat Response is installed and return true by default.
	 * If set to false, then the boolean false will be returned if we're unable to access
	 *  installed solutions or if we otherwise can't determine whether Threat Response is
	 *  installed in the Tanium environment.
	 * @private
	 */
	_isThreatResponseInstalled: function(returnTrueOnFailure) {
		var installedSolutions, threatResponseInstalled;
		returnTrueOnFailure = (typeof returnTrueOnFailure == 'undefined') ? true : returnTrueOnFailure;

		try {
			installedSolutions = this.getInstalledSolutions();
			threatResponseInstalled = installedSolutions.Tanium_Threat_Response.installed;
			return !!threatResponseInstalled; //Cast to boolean
		} catch(ex) {
			gs.debug(
				'Unable to determine if Threat Response is installed, probably because the ' +
				'API service account being used does not have sufficient permissions to ' +
				'read the installed solutions from the Tanium instance\n' +
				'Error:\n' +
				ex.message
			);
			return returnTrueOnFailure;
		}
	},

	/**
	 * Based on the indicated Operating System, identify the correct package to use to quarantine
	 *  (or, if the second argument is set to true, UN-quarantine) an endpoint using Tanium.
	 * @param {"Windows"|"Linux"|"Mac"} operatingSystem - (not case sensitive.)
	 * @param {boolean} [getRemoveQuarantinePackageName=false] - Set this argument to TRUE in order
	 *  to retrieve the name of the package for UN-QUARANTINING an endpoint.
	 * Set it to false (or don't specify it at all) to retrieve the name of the package for
	 *  quarantining the endpoint rather than un-quarantining.
	 * @returns {"Apply Windows IPsec Quarantine"|"Apply Linux IPTables Quarantine"|"Apply Mac PF
	 * Quarantine"} - The name of the package to use for quarantining an endpoint with the
	 *     specified operating system.
	 * @private
	 */
	_getQuarantinePackageNameFromOperatingSystem : function (
		operatingSystem,
		getRemoveQuarantinePackageName
	) {
		getRemoveQuarantinePackageName = (
			typeof getRemoveQuarantinePackageName == 'undefined'
		) ? false : getRemoveQuarantinePackageName;

		switch (operatingSystem.toLowerCase()) {
			case 'windows':
				if (getRemoveQuarantinePackageName) {
					return gs.getProperty(
						'x_taniu_tan_core.windows_remove_quarantine_package_name',
						'Remove Windows IPsec Quarantine'
					);
				} else {
					return gs.getProperty(
						'x_taniu_tan_core.windows_quarantine_package_name',
						'Apply Windows IPsec Quarantine'
					);
				}
			case 'linux':
				if (getRemoveQuarantinePackageName) {
					return gs.getProperty(
						'x_taniu_tan_core.linux_remove_quarantine_package_name',
						'Remove Linux IPTables Quarantine'
					);
				} else {
					return gs.getProperty(
						'x_taniu_tan_core.linux_quarantine_package_name',
						'Apply Linux IPTables Quarantine'
					);
				}
			case 'mac':
			case 'macos':
				if (getRemoveQuarantinePackageName) {
					return gs.getProperty(
						'x_taniu_tan_core.mac_remove_quarantine_package_name',
						'Remove Mac PF Quarantine'
					);
				} else {
					return gs.getProperty(
						'x_taniu_tan_core.mac_quarantine_package_name',
						'Apply Mac PF Quarantine'
					);
				}
			default:
				throw new Error(
					'Invalid operating system ("' + operatingSystem + '") specified when ' +
					'attempting to retrieve quarantine package name. This endpoint may ' +
					'not be able to be quarantined, or may have an unsupported operating ' +
					'system for this action.'
				);
		}
	},

	/**
	 *
	 * @param packageID
	 * @return {GlideRecord}
	 * @private
	 */
	_getPackageGRByID : function (packageID) {
		var grPackage;

		grPackage = new GlideRecord('x_taniu_tan_core_tanium_package');
		grPackage.addQuery('package_id', packageID);
		grPackage.setLimit(1);
		grPackage.query();

		return grPackage;
	},

	/**
	 * @param {String|Number} packageID
	 * @param {String} [encodedQuery=] - Optionally specify an additional encoded query string to
	 *     be applied to the query.
	 * @return {GlideRecord} - A GlideRecord with a query to show only those parameters that are
	 *     children of the package with the specified ID, not yet positioned (thus, .next() must be
	 *     called to iterate into the first record). If encodedQuery is specified, then the results
	 *     will be further filtered by that query.
	 * @private
	 */
	_getParametersGRByPackageID : function (packageID, encodedQuery) {
		var grParameter;

		grParameter = new GlideRecord('x_taniu_tan_core_tanium_package_parameter');
		grParameter.addEncodedQuery('package.package_id=' + packageID);
		if (encodedQuery) {
			grParameter.addEncodedQuery(encodedQuery);
		}
		grParameter.query();

		return grParameter;
	},

	/**
	 *
	 * @param packageID
	 * @param parameterKeysArr
	 * @return {{invalid_parameter_keys: any, err_msg: string, specified_parameter_keys, has_error:
	 *     boolean}}
	 * @private
	 */
	_checkAllParametersAreValidForPackage : function (packageID, parameterKeysArr) {
		var parameterKey, grParameter, keyIndex;
		var paramValidationResponse = {
			'has_error' : false,
			'err_msg' : '',
			'specified_parameter_keys' : parameterKeysArr,
			'invalid_parameter_keys' : JSON.parse(JSON.stringify(parameterKeysArr))
		};

		grParameter = this._getParametersGRByPackageID(
			packageID,
			'keyIN' + parameterKeysArr.join(',')
		);

		while (grParameter.next()) {
			parameterKey = grParameter.getValue('key');
			keyIndex = paramValidationResponse.invalid_parameter_keys.indexOf(parameterKey);

			if (keyIndex >= 0) {
				//Remove the found (valid) parameter from the invalid parameter keys array
				paramValidationResponse.invalid_parameter_keys.splice(keyIndex, 1);
			}
		}

		if (paramValidationResponse.invalid_parameter_keys.length > 0) {
			paramValidationResponse.has_error = true;
			paramValidationResponse.err_msg = 'Could not find the following parameters which ' +
				'were specified, in the list of valid parameters for the Tanium package with ID ' +
				packageID + ':\n' +
				paramValidationResponse.invalid_parameter_keys.join(', ');
		}

		return paramValidationResponse;
	},

	/**
	 *
	 * @param parametersObj
	 * @return {*[]}
	 * @private
	 */
	_transformParametersObjToArray : function (parametersObj) {
		var paramKey, paramValue;
		var parametersArray = [];

		for (paramKey in parametersObj) {
			//Prevent iteration into non-own properties
			if (!parametersObj.hasOwnProperty(paramKey)) {
				continue;
			}
			paramValue = parametersObj[paramKey];

			parametersArray.push({
				'key' : paramKey,
				'value' : paramValue
			});
		}

		return parametersArray;
	},

	/**
	 *
	 * @param allPackages
	 * @param removeHiddenPackages
	 * @param removeDeletedPackages
	 * @return {*}
	 * @private
	 */
	_updateAndDeleteExistingPackages : function (allPackages, removeHiddenPackages, removeDeletedPackages) {
		var grPackage, packageID;

		removeHiddenPackages = (typeof removeHiddenPackages == 'undefined') ? true : removeHiddenPackages;
		removeDeletedPackages = (typeof removeDeletedPackages == 'undefined') ? true : removeDeletedPackages;

		grPackage = new GlideRecord('x_taniu_tan_core_tanium_package');
		grPackage.query();

		while (grPackage.next()) {
			try {
				packageID = grPackage.getValue('package_id');

				//If latest package import does not contain the record's package ID, delete
				// the Package record in the Tanium Package table and continue to next loop.
				if (!allPackages.hasOwnProperty(packageID)) {
					grPackage.deleteRecord();
					continue;
				}

				//If package has been hidden and removeHiddenPackages is true, delete record.
				if (
					allPackages[packageID].hasOwnProperty('hidden_flag') &&
					allPackages[packageID].hidden_flag &&
					removeHiddenPackages
				) {
					//Delete package record. The "Cascade Delete Params when Pkg Deleted" BR
					// deletes Parameters when Packages are deleted, so it's not necessary to
					// do that manually here.
					grPackage.deleteRecord();
					//Remove the package we just deleted from the packages list
					delete allPackages[packageID];
					continue;
				}

				//If package has been deleted and removeDeletedPackages is true, delete record.
				if (
					allPackages[packageID].hasOwnProperty('deleted_flag') &&
					allPackages[packageID].deleted_flag &&
					removeDeletedPackages
				) {
					//Delete package record. The "Cascade Delete Params when Pkg Deleted" BR
					// deletes Parameters when Packages are deleted, so it's not necessary to
					// do that manually here.
					grPackage.deleteRecord();
					//Remove the package we just deleted from the packages list
					delete allPackages[packageID];
					continue;
				}

				//If package IS found in the latest import, populate the package record with the
				// latest data.
				grPackage = this._populatePackageRecord(grPackage, allPackages[packageID]);

				//Update the package record.
				//NOTE: If the info in the record hasn't changed since the last update, this will
				// do nothing and not impact performance.
				grPackage.update();
				//Add, update, or delete package parameter records associated with this package
				this._addUpdateDeletePackageParameters(
					grPackage.getValue('sys_id'),
					allPackages[packageID]
				);

				//Remove the package we just updated from the packages list
				delete allPackages[packageID];
			} catch (ex) {
				gs.error(
					'Error updating Tanium Software Package with sys_id ' +
					grPackage.getUniqueValue() + ' or one of its parameters.\n' +
					'Error: ' + ex.message + '\nContinuing to next package.'
				);
			}
		}

		//NOTE: This method modifies allPackages in-place, so this return is just for consistency.
		return allPackages;
	},

	/**
	 *
	 * @param packagesToCreate
	 * @param skipHiddenPackages
	 * @param skipDeletedPackages
	 * @private
	 */
	_createAllMissingPackages : function (packagesToCreate, skipHiddenPackages, skipDeletedPackages) {
		var grPackage, packageID;

		skipHiddenPackages = (typeof skipHiddenPackages == 'undefined') ? true : skipHiddenPackages;
		skipDeletedPackages = (typeof skipDeletedPackages == 'undefined') ? true : skipDeletedPackages;

		grPackage = new GlideRecord('x_taniu_tan_core_tanium_package');

		for (packageID in packagesToCreate) {
			try {
				//Prevent iteration into non-own properties
				if (!packagesToCreate.hasOwnProperty(packageID)) {
					continue;
				}

				//Initialize, populate, and insert the new record.
				grPackage.initialize();
				this._populatePackageRecord(grPackage, packagesToCreate[packageID]);
				grPackage.insert();

				//Add, update, or delete package parameter records associated with this package
				this._addUpdateDeletePackageParameters(
					grPackage.getValue('sys_id'),
					packagesToCreate[packageID]
				);
			} catch (ex) {
				gs.debug(
					'Error creating Tanium Software Package with id ' + packageID + ' or one ' +
					'of its parameters.\n' +
					'Error: ' + ex.message + '\n' +
					'Continuing to next package.'
				);
			}
		}
	},

	/**
	 *
	 * @param grPackage
	 * @param packageObj
	 * @return {*}
	 * @private
	 */
	_populatePackageRecord : function (grPackage, packageObj) {
		//This method is reused by both the "update package record" method and the "create package
		// record" method.
		var snFieldName, snFieldVal;
		var packageFields = {
			'name' : packageObj.name.toString(), //mandatory
			'package_id' : packageObj.id.toString() //mandatory
		};
		if (packageObj.hasOwnProperty('command')) {
			packageFields['command'] = packageObj.command.toString();
		}
		if (packageObj.hasOwnProperty('content_set')) {
			if (packageObj.content_set.hasOwnProperty('id')) {
				packageFields['content_set_id'] = packageObj.content_set.id.toString();
			}
			if (packageObj.content_set.hasOwnProperty('name')) {
				packageFields['content_set_name'] = packageObj.content_set.name.toString();
			}
		}

		for (snFieldName in packageFields) {
			//Prevent iteration into non-own properties
			if (!packageFields.hasOwnProperty(snFieldName)) {
				continue;
			}

			snFieldVal = packageFields[snFieldName];
			grPackage.setValue(snFieldName, snFieldVal);
		}

		//NOTE: Returns grPackage WITHOUT updating. That must be done by the calling code.
		//Also modifies grPackage in-place so this return is mostly just for consistency.
		return grPackage;
	},

	/**
	 *
	 * @param packageSysID
	 * @param packageObj
	 * @private
	 */
	_addUpdateDeletePackageParameters : function (packageSysID, packageObj) {
		var parametersObj;

		parametersObj = this._getAllParametersFromPackage(packageObj);

		//Mutates (deletes processed parameters) the parametersObj object in-place.
		if (parametersObj) {
			this._updateAndDeleteExistingParameters(packageSysID, parametersObj);
			this._createAllMissingParameters(packageSysID, parametersObj);
		}

	},

	/**
	 *
	 * @param packageSysID
	 * @param parametersObj
	 * @return {*}
	 * @private
	 */
	_updateAndDeleteExistingParameters : function (packageSysID, parametersObj) {
		var parameterKey;
		var grPackageParameter = new GlideRecord('x_taniu_tan_core_tanium_package_parameter');

		grPackageParameter.addQuery('package', packageSysID);
		grPackageParameter.query();

		while (grPackageParameter.next()) {
			parameterKey = grPackageParameter.getValue('key');
			//If the most recent package export doesn't contain a parameter for this package
			// with the key indicated in this record, delete the parameter record and continue
			// to the next loop.
			if (!parametersObj.hasOwnProperty(parameterKey)) {
				grPackageParameter.deleteRecord();
				continue;
			}

			//If parameter IS found in the latest import, populate the param record with the latest
			// data.
			grPackageParameter = this._populateParameterRecord(
				grPackageParameter,
				packageSysID,
				parametersObj[parameterKey]
			);

			//Update the parameter record.
			//NOTE: If the info in the record hasn't changed since the last update, this will
			// do nothing and not impact performance.
			grPackageParameter.update();

			//Remove the parameter we just updated from the packages list
			delete parametersObj[parameterKey];
		}

		//NOTE: This method modifies allPackages in-place, so this return is just for consistency.
		return parametersObj;
	},

	/**
	 *
	 * @param packageSysID
	 * @param parametersToCreate
	 * @private
	 */
	_createAllMissingParameters : function (packageSysID, parametersToCreate) {
		var parameterKey;
		var grPackageParameter = new GlideRecord('x_taniu_tan_core_tanium_package_parameter');

		for (parameterKey in parametersToCreate) {
			//Prevent iteration into non-own properties
			if (!parametersToCreate.hasOwnProperty(parameterKey)) {
				continue;
			}

			//Initialize, populate, and insert the new record.
			grPackageParameter.initialize();
			this._populateParameterRecord(
				grPackageParameter,
				packageSysID,
				parametersToCreate[parameterKey]
			);
			grPackageParameter.insert();
		}
	},

	/**
	 *
	 * @param grParameter
	 * @param packageSysID
	 * @param parametersObj
	 * @return {*}
	 * @private
	 */
	_populateParameterRecord : function (grParameter, packageSysID, parametersObj) {
		//This method is reused by both the "update/delete parameter record" method
		// and the "create parameter record" method.
		var snFieldName, snFieldVal;
		var paramDescription = '';
		var parameterFields = {
			//Mandatory key
			'key' : parametersObj.key.toString(),
			//Mandatory - default to key if label not present.
			'label' : (parametersObj.label.toString() || parametersObj.key.toString()),
			'package' : packageSysID //mandatory
		};

		if (parametersObj.hasOwnProperty('maxChars')) {
			parameterFields['max_characters'] = parametersObj.maxChars.toString();
		}

		if (parametersObj.hasOwnProperty('helpString') && parametersObj.helpString) {
			paramDescription += parametersObj.helpString.toString();
		}

		if (parametersObj.hasOwnProperty('promptText') && parametersObj.promptText) {
			if (paramDescription) {
				paramDescription += '\n\n';
			}
			paramDescription += parametersObj.promptText.toString();
		}

		parameterFields['description'] = paramDescription;

		for (snFieldName in parameterFields) {
			//Prevent iteration into non-own properties
			if (!parameterFields.hasOwnProperty(snFieldName)) {
				continue;
			}

			snFieldVal = parameterFields[snFieldName];
			grParameter.setValue(snFieldName, snFieldVal);
		}

		//NOTE: Returns grParameter WITHOUT updating. That must be done by the calling code.
		//Also modifies grParameter in-place so this return is mostly just for consistency.
		return grParameter;
	},

	/**
	 *
	 * @param packageObj
	 * @return {{}|boolean}
	 * @private
	 */
	_getAllParametersFromPackage : function (packageObj) {
		var i, parametersArr;
		var parametersObj = {};

		if (
			!packageObj.hasOwnProperty('parameter_definition') ||
			!packageObj.parameter_definition
		) {
			return false;
		}

		try {
			parametersArr = JSON.parse(packageObj.parameter_definition);
			parametersArr = parametersArr.parameters; //Get array of parameters
		} catch (ex) {
			gs.warn(
				'Unparseable parameter_definition node for Tanium Package with ID ' +
				packageObj.id + '. This is occasionally expected on a FEW parameters, but if ' +
				'this happens for all/most of them, there may be a problem.'
			);
			return false;
		}

		for (i = 0; i < parametersArr.length; i++) {
			if (
				!parametersArr[i].hasOwnProperty('key') || //Key property doesn't exist
				!parametersArr[i].key //Key property is falsy (null/undefined/blank/etc.)
			) {
				gs.debug(
					'Parameter found without key value. Skipping parameter on import: \n' +
					JSON.stringify(parametersArr[i], null, 2) + '\n' +
					'Note: This is not an error. This is expected to happen in some cases. ' +
					'This log is just for auditing/troubleshooting purposes, in case ' +
					'something has gone wrong.'
				);
				continue;
			}

			parametersObj[parametersArr[i].key.toString()] = parametersArr[i];
		}

		return parametersObj;
	},

	/**
	 *
	 * @return {{}}
	 * @private
	 */
	_getAllPackageDetails : function () {
		var i, responseBody, packageID;
		var packageDetails = {};
		var rGetPackages = this._getRESTObject(
			'Tanium Integration Core',
			'Action-Get All Packages'
		);

		rGetPackages.setStringParameterNoEscape('tanium_api_endpoint', this.TANIUM_API_ENDPOINT);
		responseBody = this._executeRESTCall(rGetPackages);

		//If package details response is invalid, throw an error.
		if (!responseBody.hasOwnProperty('data')) {
			throw new Error(
				'Data node missing from package details from Tanium. Something has gone wrong. ' +
				'Response payload: \n' + responseBody
			);
		}

		responseBody = responseBody.data;

		for (i = 0; i < responseBody.length; i++) {
			//Prevent iteration into weird element that isn't related to a package.
			if (!responseBody[i].hasOwnProperty('id')) {
				continue;
			}

			packageID = responseBody[i].id.toString();

			//If node already exists with this package ID, log an error and continue to next loop.
			if (packageDetails.hasOwnProperty(packageID)) {
				gs.warn(
					'Package with ID ' + packageID + ' is a duplicate. Already found ' +
					'package with this ID.'
				);
				continue;
			}

			packageDetails[packageID] = responseBody[i];
		}

		return packageDetails;
	},

	type : 'TaniumActionUtil'
});
